  // Mock info per date (e.g. events, availability, etc.)
  const mockInfo: Record<string, string> = {}
  for (let i = 0; i < 30; i++) {
    const d = new Date()
    d.setDate(d.getDate() + i)
    const dateKey = format(d, "yyyy-MM-dd")
