      <CalendarPlanner
        value={selected}
        onChange={setSelected}
        info={mockInfo}
        yearRange={[1995, 2035]}
      />
      {selected && (
        <p className="text-sm text-muted-foreground">
          Selected: {selected.toDateString()}
        </p>
      )}
    </div>
  )
}

